INSERT INTO tb_feedback_ortu (id_feedback, id_ortu, id_sp, isi_feedback, status_baca) VALUES
(2000, 317, 2000, 'Maaf sekali, kemarin Budi Kusuma bangun kesiangan karena membantu saya di pasar. Saya janji tidak akan terulang lagi.', 'Sudah Dibaca'),
(2001, 114, 2002, 'Maaf sekali, kemarin Nabila Sutrisno bangun kesiangan karena membantu saya di pasar. Saya janji tidak akan terulang lagi.', 'Sudah Dibaca'),
(2002, 230, 2003, 'Saya sangat menyesal mendengar kabar ini dari pihak sekolah. Saya sebagai orang tua akan melakukan pembinaan lebih tegas lagi di rumah.', 'Sudah Dibaca'),
(2003, 178, 2004, 'Maaf sekali, kemarin Fajar Sitorus bangun kesiangan karena membantu saya di pasar. Saya janji tidak akan terulang lagi.', 'Sudah Dibaca'),
(2004, 254, 2008, 'Aduh, saya kaget melihat poin Eka Wahyudi sudah segitu. Mohon bimbingannya bapak/ibu, saya akan segera ke sekolah.', 'Sudah Dibaca'),
(2005, 218, 2011, 'Aduh, saya kaget melihat poin Keysha Hidayatullah sudah segitu. Mohon bimbingannya bapak/ibu, saya akan segera ke sekolah.', 'Sudah Dibaca'),
(2006, 259, 2012, 'Anak saya Taufik Wibowo bilang dia hanya ikut-ikutan teman. Tapi saya tetap minta maaf dan akan membina dia lebih baik lagi.', 'Sudah Dibaca'),
(2007, 215, 2013, 'Aduh, saya kaget melihat poin Siska Saputra sudah segitu. Mohon bimbingannya bapak/ibu, saya akan segera ke sekolah.', 'Sudah Dibaca'),
(2008, 215, 2014, 'Aduh, saya kaget melihat poin Siska Saputra sudah segitu. Mohon bimbingannya bapak/ibu, saya akan segera ke sekolah.', 'Sudah Dibaca'),
(2009, 190, 2016, 'Anak saya Ratna Ramadhan bilang dia hanya ikut-ikutan teman. Tapi saya tetap minta maaf dan akan membina dia lebih baik lagi.', 'Sudah Dibaca'),
